<style scoped lang="scss">
.sp-filter-form {
  margin-bottom: 16px;
}
</style>

<template>
  <div class="page-body">
    <div class="action-container">
      <el-button
        type="primary"
        icon="iconfont icon-xinzengcaozuo-01"
        @click="addTemplate"
      >
        新增標籤
      </el-button>
    </div>

    <SpFilterForm
      :model="params"
      @onSearch="onSearch"
      @onReset="onReset"
    >
      <SpFilterFormItem
        prop="tag_name"
        label="標籤名稱:"
      >
        <el-input
          v-model="params.tag_name"
          placeholder="標籤名稱"
        />
      </SpFilterFormItem>
    </SpFilterForm>

    <el-table
      v-loading="loading"
      border
      :data="tableList"
      :height="wheight - 130"
    >
      <el-table-column
        prop="tag_id"
        label="ID"
        width="100"
      />
      <el-table-column
        prop="tag_name"
        label="標籤名稱"
        width="250"
      >
        <template slot-scope="scope">
          <el-tag
            :style="{ color: scope.row.font_color, backgroundColor: scope.row.tag_color }"
            size="mini"
          >
            {{ scope.row.tag_name }}
          </el-tag>
        </template>
      </el-table-column>
      <el-table-column
        prop="description"
        label="標籤描述"
        width="250"
      />
      <el-table-column label="操作">
        <template slot-scope="scope">
          <div class="operating-icons">
            <i
              class="iconfont icon-edit1"
              @click="editAction(scope.$index, scope.row)"
            />
            <i
              class="mark iconfont icon-trash-alt1"
              @click="deleteAction(scope.$index, scope.row)"
            />
          </div>
        </template>
      </el-table-column>
    </el-table>
    <div
      v-if="params.total_count > params.page_size"
      class="content-center content-top-padded"
    >
      <el-pagination
        layout="prev, pager, next"
        :current-page.sync="page.pageIndex"
        :total="page.total"
        :page-size="page.page_size"
        @current-change="onCurrentChange"
        @size-change="onSizeChange"
      />
    </div>
    <el-dialog
      title="新增、編輯標籤"
      width="40%"
      :visible.sync="memberTagDialog"
      :before-close="handleCancelLabelsDialog"
    >
      <template>
        <el-form
          ref="form"
          :model="form"
          class="demo-ruleForm"
          label-width="100px"
        >
          <el-form-item label="預覽最終結果">
            <el-tag
              :color="form.tag_color"
              size="mini"
              :style="'color:' + form.font_color"
            >
              {{ form.tag_name }}
            </el-tag>
          </el-form-item>
          <el-form-item
            class="content-left"
            label="標籤名稱"
            prop="tag_name"
            :rules="[{ required: true, message: '請輸入標籤名稱', trigger: 'blur' }]"
          >
            <el-input
              v-model="form.tag_name"
              placeholder="請輸入標籤名稱"
            />
          </el-form-item>
          <el-form-item
            class="content-left"
            label="標籤說明"
          >
            <el-input
              v-model="form.description"
              type="textarea"
              :rows="3"
              placeholder="請輸入標籤說明"
            />
          </el-form-item>
          <el-form-item
            class="content-left"
            label="標籤顏色"
          >
            <el-color-picker
              v-model="form.tag_color"
              show-alpha
              :predefine="predefineColors"
            />
          </el-form-item>
          <el-form-item
            class="content-left"
            label="字體顏色"
          >
            <el-color-picker
              v-model="form.font_color"
              show-alpha
              :predefine="predefineColors"
            />
          </el-form-item>
          <el-form-item
            class="content-left"
            label="前台顯示"
          >
            <el-radio-group
              v-model="form.front_show"
              size="small"
            >
              <el-radio
                label="1"
                border
              >
                顯示
              </el-radio>
              <el-radio
                label="0"
                border
              >
                不顯示
              </el-radio>
            </el-radio-group>
          </el-form-item>
          <el-form-item class="content-center">
            <el-button
              type="primary"
              @click="saveTagData"
            >
              確定儲存
            </el-button>
          </el-form-item>
        </el-form>
      </template>
    </el-dialog>
  </div>
</template>
<script>
import { mapGetters } from 'vuex'
import { saveTag, getTagList, updateTag, deleteTag } from '@/api/marketing'
import mixin, { pageMixin } from '@/mixins'
export default {
  mixins: [mixin, pageMixin],
  data () {
    return {
      isEdit: false,
      loading: false,
      params: {
        tag_name: ''
      },
      form: {
        tag_id: '',
        tag_name: '',
        tag_color: '#ff1939',
        font_color: '#ffffff',
        description: '',
        front_show: '0'
      },
      memberTagDialog: false,
      predefineColors: ['#ff4500', '#ff8c00', '#ffd700', '#90ee90', '#00ced1', '#1e90ff', '#c71585']
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  },
  mounted () {
    this.fetchList()
  },
  methods: {
    addTemplate () {
      // 新增商品
      this.memberTagDialog = true
      this.form = {
        tag_id: '',
        tag_name: '',
        tag_color: '#ff1939',
        font_color: '#ffffff',
        description: '',
        front_show: '0'
      }
    },
    onSearch () {
      this.page.pageIndex = 1
      this.$nextTick(() => {
        this.fetchList()
      })
    },
    onReset () {
      this.params = { ...this.initialParams }
      this.onSearch()
    },
    editAction (index, row) {
      // 編輯商品彈框
      this.form = row
      this.memberTagDialog = true
    },
    async fetchList () {
      this.loading = true
      const { pageIndex: page, pageSize } = this.page
      let params = {
        page,
        pageSize,
        ...this.params
      }
      const { list, total_count } = await this.$api.marketing.getTagList(params)
      this.tableList = list
      this.page.total = total_count
      this.loading = false
    },

    deleteAction (index, row) {
      this.$confirm('此操作將刪除數據, 是否繼續?', '提示', {
        confirmButtonText: '確定',
        cancelButtonText: '取消',
        type: 'warning'
      })
        .then(() => {
          deleteTag(row.tag_id)
            .then((response) => {
              // this.tagsList.splice(index, 1)
              this.$message({
                message: '刪除成功',
                type: 'success',
                duration: 5 * 1000
              })
              this.onSearch()
            })
            .catch(() => {
              this.$message({
                type: 'error',
                message: '刪除失敗'
              })
            })
        })
        .catch(() => {
          this.$message({
            type: 'info',
            message: '已取消'
          })
        })
    },
    getTaskTime (strDate) {
      let date = new Date(strDate)
      let y = date.getFullYear()
      let m = date.getMonth() + 1
      m = m < 10 ? '0' + m : m
      let d = date.getDate()
      d = d < 10 ? '0' + d : d
      let str = y + '-' + m + '-' + d
      return str
    },
    getTimeStr (date) {
      return this.getTaskTime(new Date(parseInt(date) * 1000))
    },
    handleCancelLabelsDialog () {
      this.memberTagDialog = false
    },
    saveTagData () {
      if (this.form.tag_id) {
        updateTag(this.form.tag_id, this.form).then((res) => {
          if (res.data.data) {
            this.$message({
              type: 'success',
              message: '儲存成功'
            })
            this.memberTagDialog = false
            this.onSearch()
          }
        })
      } else {
        saveTag(this.form).then((res) => {
          if (res.data.data) {
            this.$message({
              type: 'success',
              message: '儲存成功'
            })
            this.memberTagDialog = false
            this.onSearch()
          }
        })
      }
    }
  }
}
</script>
